using System;
using System.Collections;
using TMPro;
using UnityEngine;

/// <summary>
/// Tela de morte (Tarefa #16 — "verificação final: tela de morte, loading e
/// save 100%/101%"): overlay full-screen (CanvasGroup, Screen Space -
/// Overlay) mostrado quando PlayerProgress.OnHeartsDepleted dispara
/// (PlayerDeathHandler liga-se a este evento).
///
/// Singleton com auto-fallback (mesmo padrão de PlayerProgress/GameVariables —
/// ver Tarefa #15).
///
/// Montagem no Editor:
/// - Canvas (Screen Space - Overlay, sortingOrder alto — acima do HUD e do
///   Menu de Pausa) com um "panelRoot" (Image full-screen, ex: preto/vermelho
///   escuro) + "canvasGroup" no mesmo GameObject.
/// - "messageText" (TMP_Text): ex. "Perdeste os sentidos...".
/// - "deathSfx" (opcional): som ao mostrar a tela.
/// </summary>
public class DeathScreenUI : MonoBehaviour
{
    public static DeathScreenUI Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private TMP_Text messageText;

    [Header("Texto")]
    [SerializeField] private string deathMessage = "Perdeste os sentidos...";

    [Header("Transição")]
    [Tooltip("Duração do fade in/out do overlay, em segundos.")]
    [SerializeField] private float fadeDuration = 0.5f;

    [Tooltip("Tempo (s) com o overlay totalmente visível antes do callback de reaparecimento ser chamado.")]
    [SerializeField] private float holdDuration = 1f;

    [Header("Som")]
    [SerializeField] private AudioClip deathSfx;

    private bool isAutoFallback;
    private bool isShowing;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (canvasGroup != null)
        {
            canvasGroup.alpha = 0f;
            canvasGroup.blocksRaycasts = false;
        }

        if (panelRoot != null) panelRoot.SetActive(false);
        if (messageText != null) messageText.text = deathMessage;
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(DeathScreenUI) + " (Fallback)");
        var instance = go.AddComponent<DeathScreenUI>();
        instance.isAutoFallback = true;
    }

    public bool IsShowing => isShowing;

    /// <summary>
    /// Fade in do overlay de morte → espera "holdDuration" → chama "onRespawn"
    /// (PlayerDeathHandler reposiciona/recupera o player AQUI, enquanto o
    /// overlay ainda cobre o ecrã) → fade out.
    /// </summary>
    public void PlayDeathSequence(Action onRespawn)
    {
        if (isShowing) return;
        StartCoroutine(DeathSequenceRoutine(onRespawn));
    }

    private IEnumerator DeathSequenceRoutine(Action onRespawn)
    {
        isShowing = true;

        // Sem CanvasGroup configurado (ex.: instância "Fallback" auto-criada
        // sem UI montada no Editor) — sem overlay, mas a sequência continua
        // (espera + respawn) para não bloquear o jogo.
        if (canvasGroup == null)
        {
            AudioManager.Instance?.PlaySE(deathSfx);

            float tNoUi = 0f;
            while (tNoUi < holdDuration)
            {
                tNoUi += Time.unscaledDeltaTime;
                yield return null;
            }

            onRespawn?.Invoke();
            isShowing = false;
            yield break;
        }

        if (panelRoot != null) panelRoot.SetActive(true);
        canvasGroup.blocksRaycasts = true;

        AudioManager.Instance?.PlaySE(deathSfx);

        yield return FadeRoutine(0f, 1f);

        float t = 0f;
        while (t < holdDuration)
        {
            t += Time.unscaledDeltaTime;
            yield return null;
        }

        onRespawn?.Invoke();

        yield return FadeRoutine(1f, 0f);

        canvasGroup.blocksRaycasts = false;
        if (panelRoot != null) panelRoot.SetActive(false);

        isShowing = false;
    }

    private IEnumerator FadeRoutine(float from, float to)
    {
        if (canvasGroup == null) yield break;

        canvasGroup.alpha = from;

        if (fadeDuration <= 0f)
        {
            canvasGroup.alpha = to;
            yield break;
        }

        float t = 0f;
        while (t < fadeDuration)
        {
            t += Time.unscaledDeltaTime;
            canvasGroup.alpha = Mathf.Lerp(from, to, t / fadeDuration);
            yield return null;
        }
        canvasGroup.alpha = to;
    }
}
